// Load persisted cursors per institution from workflow static data.
// First run: cursors are empty strings, Plaid returns ALL historical transactions.
const staticData = $getWorkflowStaticData('global');
if (!staticData.cursors) staticData.cursors = {};

const institutions = [
  { name: 'chase', access_token_cred: 'PLAID_ACCESS_TOKEN_CHASE' },
  { name: 'capital_one', access_token_cred: 'PLAID_ACCESS_TOKEN_CAPITAL_ONE' },
  { name: 'synchrony', access_token_cred: 'PLAID_ACCESS_TOKEN_SYNCHRONY' }
];

return institutions.map(inst => ({
  json: {
    institution: inst.name,
    access_token_cred: inst.access_token_cred,
    cursor: staticData.cursors[inst.name] || ''
  }
}));

// Persist the new cursor for each institution so next run only gets new changes.
const staticData = $getWorkflowStaticData('global');
if (!staticData.cursors) staticData.cursors = {};

const incoming = $input.all();
const institutions = ['chase', 'capital_one', 'synchrony'];

const rowsToUpsert = [];
const rowsToDelete = [];

incoming.forEach((batch, idx) => {
  const instName = institutions[idx];
  const data = batch.json;

  // Save cursor for next run
  if (data.next_cursor) {
    staticData.cursors[instName] = data.next_cursor;
  }

  // Added + modified → upsert
  const touched = [...(data.added || []), ...(data.modified || [])];
  touched.forEach(tx => rowsToUpsert.push({ json: { ...tx, __institution: instName, __op: 'upsert' } }));

  // Removed → delete from Notion
  (data.removed || []).forEach(tx => rowsToDelete.push({ json: { transaction_id: tx.transaction_id, __op: 'delete' } }));
});

return [...rowsToUpsert, ...rowsToDelete];

// Map one Plaid transaction → Notion property payload.
// Only runs on 'upsert' items; delete items passed through untouched.
const tx = $json;
if (tx.__op === 'delete') return [{ json: tx }];

// --- Account mapping: fill in real Plaid account_id values after linking ---
const accountMap = {
  'PLAID_ACCOUNT_ID_CHASE_CHECKING': 'Chase Checking',
  'PLAID_ACCOUNT_ID_CHASE_AUTO': 'Chase Auto',
  'PLAID_ACCOUNT_ID_CHASE_FREEDOM': 'Chase Freedom',
  'PLAID_ACCOUNT_ID_CAPITAL_ONE_PLATINUM': 'Capital One Platinum',
  'PLAID_ACCOUNT_ID_CAPITAL_ONE_QUICKSILVER': 'Capital One Quicksilver',
  'PLAID_ACCOUNT_ID_SYNCHRONY_AMAZON': 'Synchrony Amazon'
};
const friendlyAccount = accountMap[tx.account_id] || 'Uncategorized';

// Plaid convention: amount > 0 = money leaving the account (expense).
//                   amount < 0 = money entering (income/refund).
const isIncome = tx.amount < 0;
const type = tx.pending ? 'Expense' : (isIncome ? 'Income' : 'Expense');

// Map Plaid PFC (personal_finance_category.primary) → our Notion categories
const pfcMap = {
  'FOOD_AND_DRINK': 'Food & Drink',
  'GENERAL_MERCHANDISE': 'Shopping',
  'TRANSPORTATION': 'Transportation',
  'TRAVEL': 'Travel',
  'ENTERTAINMENT': 'Entertainment',
  'RENT_AND_UTILITIES': 'Utilities',
  'MEDICAL': 'Medical',
  'PERSONAL_CARE': 'Personal Care',
  'GENERAL_SERVICES': 'Subscriptions',
  'INCOME': 'Paycheck',
  'TRANSFER_IN': 'Transfer',
  'TRANSFER_OUT': 'Transfer',
  'LOAN_PAYMENTS': 'Credit Card Payment',
  'BANK_FEES': 'Fees & Interest'
};
const pfc = tx.personal_finance_category?.primary;
let category = pfcMap[pfc] || 'Uncategorized';

// Groceries heuristic — Plaid buckets grocery under FOOD_AND_DRINK but the detailed tag distinguishes
if (tx.personal_finance_category?.detailed === 'FOOD_AND_DRINK_GROCERIES') category = 'Groceries';
if (tx.personal_finance_category?.detailed?.includes('GAS')) category = 'Gas';

return [{
  json: {
    __op: 'upsert',
    transaction_id: tx.transaction_id,
    notion_properties: {
      'Name': tx.merchant_name || tx.name || 'Unknown',
      'Amount': tx.amount,
      'Date': { start: tx.date },
      'Type': type,
      'Category': category,
      'Account': friendlyAccount,
      'Status': tx.pending ? 'Pending' : 'Posted',
      'Merchant': tx.merchant_name || '',
      'Plaid Transaction ID': tx.transaction_id,
      'Plaid Account ID': tx.account_id
    }
  }
}];
